"use client";
import { memo } from 'react';
import { motion } from 'framer-motion';
import {
  BarChart,
  Bar,
  CartesianGrid,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
} from 'recharts';

export interface BarPoint {
  name: string;
  value: number;
}

interface EventsBarChartProps {
  data: BarPoint[];
}

const fadeSlide = {
  initial: { opacity: 0, y: 14 },
  animate: { opacity: 1, y: 0 },
};

function EventsBarChartBase({ data }: EventsBarChartProps) {
  return (
    <motion.div {...fadeSlide} transition={{ duration: 0.35 }} className="h-64 w-full">
      <ResponsiveContainer width="100%" height="100%">
        <BarChart data={data} margin={{ top: 8, right: 8, left: 0, bottom: 8 }}>
          <CartesianGrid strokeDasharray="3 3" stroke="#E9D5FF" />
          <XAxis dataKey="name" tick={{ fill: '#6B21A8' }} />
          <YAxis tick={{ fill: '#6B21A8' }} />
          <Tooltip
            contentStyle={{ borderRadius: 12, borderColor: '#E9D5FF' }}
            cursor={{ fill: 'rgba(139,92,246,0.08)' }}
          />
          <Bar dataKey="value" fill="#7C3AED" radius={[8, 8, 0, 0]} />
        </BarChart>
      </ResponsiveContainer>
    </motion.div>
  );
}

export default memo(EventsBarChartBase);
